import{_ as o,c as e,o as t,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Google Cloud 할당량 조회 | opencode-mystatus","description":"Google Cloud 할당량 조회 방법을 학습합니다. G3 Pro, Image, Flash, Claude 모델의 남은 할당량과 재설정 시간을 확인합니다.","frontmatter":{"title":"Google Cloud 할당량 조회 | opencode-mystatus","sidebarTitle":"Google 할당량","subtitle":"Google Cloud 할당량 조회: G3 Pro/Image/Flash 및 Claude","description":"Google Cloud 할당량 조회 방법을 학습합니다. G3 Pro, Image, Flash, Claude 모델의 남은 할당량과 재설정 시간을 확인합니다.","tags":["Google Cloud","Antigravity","할당량 조회"],"prerequisite":["start-quick-start","start-using-mystatus"],"order":4},"headers":[],"relativePath":"ko/vbgate/opencode-mystatus/platforms/google-usage/index.md","filePath":"ko/vbgate/opencode-mystatus/platforms/google-usage/index.md"}'),s={name:"ko/vbgate/opencode-mystatus/platforms/google-usage/index.md"};function i(n,a,d,r,p,c){return t(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="google-cloud-할당량-조회-g3-pro-image-flash-및-claude" tabindex="-1">Google Cloud 할당량 조회: G3 Pro/Image/Flash 및 Claude <a class="header-anchor" href="#google-cloud-할당량-조회-g3-pro-image-flash-및-claude" aria-label="Permalink to &quot;Google Cloud 할당량 조회: G3 Pro/Image/Flash 및 Claude&quot;">​</a></h1><h2 id="학습-완료-후-할-수-있는-것" tabindex="-1">학습 완료 후 할 수 있는 것 <a class="header-anchor" href="#학습-완료-후-할-수-있는-것" aria-label="Permalink to &quot;학습 완료 후 할 수 있는 것&quot;">​</a></h2><ul><li>Google Cloud Antigravity 계정의 4개 모델 할당량 보기</li><li>각 모델의 재설정 시간 및 남은 비율 이해</li><li>여러 Google Cloud 계정의 할당량 사용 관리</li></ul><h2 id="현재-문제-상황" tabindex="-1">현재 문제 상황 <a class="header-anchor" href="#현재-문제-상황" aria-label="Permalink to &quot;현재 문제 상황&quot;">​</a></h2><p>Google Cloud Antigravity는 여러 모델(G3 Pro, G3 Image, G3 Flash, Claude)을 제공하며, 각 모델은 독립적인 할당량과 재설정 시간이 있습니다. 귀하는 다음이 필요합니다:</p><ul><li>각 모델의 상태를 보기 위해 Google Cloud 콘솔에 각각 로그인</li><li>남은 할당량 및 재설정 시간 수동 계산</li><li>여러 계정 관리 시 더욱 혼란스러움</li></ul><h2 id="이-방법을-사용해야-할-때" tabindex="-1">이 방법을 사용해야 할 때 <a class="header-anchor" href="#이-방법을-사용해야-할-때" aria-label="Permalink to &quot;이 방법을 사용해야 할 때&quot;">​</a></h2><p>다음과 같은 상황일 때:</p><ul><li>모든 Google Cloud 모델의 남은 할당량을 빠르게 이해하고 싶을 때</li><li>다양한 모델 간의 사용 배분을 계획하고 싶을 때</li><li>여러 Google Cloud 계정을 통합 관리해야 할 때</li></ul><h2 id="🎒-시작-전-준비" tabindex="-1">🎒 시작 전 준비 <a class="header-anchor" href="#🎒-시작-전-준비" aria-label="Permalink to &quot;🎒 시작 전 준비&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">사전 확인</p><ol><li><strong>mystatus 플러그인 설치</strong>: <a href="/docs/opencodedocs/ko/vbgate/opencode-mystatus/start/quick-start/">빠른 시작</a> 참조</li><li><strong>Google Cloud 인증 완료</strong>: 먼저 <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a> 플러그인 설치하여 OAuth 인증 완료 필요</li><li><strong>인증 파일 존재</strong>: <code>~/.config/opencode/antigravity-accounts.json</code>에 최소한 하나의 계정 포함</li></ol></div><h2 id="핵심-개념" tabindex="-1">핵심 개념 <a class="header-anchor" href="#핵심-개념" aria-label="Permalink to &quot;핵심 개념&quot;">​</a></h2><p>Google Cloud Antigravity는 OAuth 메커니즘을 통해 인증하며, 각 계정은 독립적인 새로 고침 토큰이 있습니다. mystatus 플러그인은 다음을 수행합니다:</p><ol><li><code>antigravity-accounts.json</code>을 읽어 모든 구성된 계정 가져오기</li><li>새로 고침 토큰을 사용하여 액세스 토큰 새로 고침</li><li>Google Cloud API를 호출하여 모든 모델의 할당량 가져오기</li><li>계정별로 4개 모델의 할당량 및 재설정 시간 표시</li></ol><h2 id="google-cloud-지원-모델" tabindex="-1">Google Cloud 지원 모델 <a class="header-anchor" href="#google-cloud-지원-모델" aria-label="Permalink to &quot;Google Cloud 지원 모델&quot;">​</a></h2><p>mystatus는 다음 4개 모델의 할당량을 표시합니다:</p><table tabindex="0"><thead><tr><th>표시 이름</th><th>모델 키(주/대체)</th><th>설명</th></tr></thead><tbody><tr><td>G3 Pro</td><td><code>gemini-3-pro-high</code> / <code>gemini-3-pro-low</code></td><td>Gemini 3 Pro 고성능 버전</td></tr><tr><td>G3 Image</td><td><code>gemini-3-pro-image</code></td><td>Gemini 3 Pro 이미지 생성</td></tr><tr><td>G3 Flash</td><td><code>gemini-3-flash</code></td><td>Gemini 3 Flash 빠른 버전</td></tr><tr><td>Claude</td><td><code>claude-opus-4-5-thinking</code> / <code>claude-opus-4-5</code></td><td>Claude Opus 4.5 모델</td></tr></tbody></table><p><strong>주 키 및 대체 키 메커니즘</strong>:</p><ul><li>API 응답은 주 키 또는 대체 키 중 하나의 데이터만 반환할 수 있음</li><li>mystatus는 자동으로 모든 키의 할당량을 가져오려고 시도함</li><li>예: <code>gemini-3-pro-high</code>에 데이터가 없으면 <code>gemini-3-pro-low</code>를 시도함</li></ul><h2 id="단계별-따라하기" tabindex="-1">단계별 따라하기 <a class="header-anchor" href="#단계별-따라하기" aria-label="Permalink to &quot;단계별 따라하기&quot;">​</a></h2><h3 id="_1단계-조회-명령-실행" tabindex="-1">1단계: 조회 명령 실행 <a class="header-anchor" href="#_1단계-조회-명령-실행" aria-label="Permalink to &quot;1단계: 조회 명령 실행&quot;">​</a></h3><p><strong>왜 필요한가</strong> 모든 Google Cloud 계정의 할당량 정보를 빠르게 가져옵니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mystatus</span></span></code></pre></div><p><strong>다음을 확인해야 합니다</strong></p><p>모든 구성된 플랫폼의 할당량 정보를 포함하며, Google Cloud 섹션은 다음과 같은 내용을 표시합니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Google Cloud Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Flash   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>Claude     2d 9h      ░░░░░░░░░░░░░░░░░░░░ 0%</span></span></code></pre></div><h3 id="_2단계-출력-형식-이해" tabindex="-1">2단계: 출력 형식 이해 <a class="header-anchor" href="#_2단계-출력-형식-이해" aria-label="Permalink to &quot;2단계: 출력 형식 이해&quot;">​</a></h3><p><strong>왜 필요한가</strong> 핵심 정보를 빠르게 파악: 남은 할당량 및 재설정 시간</p><p>각 줄 형식:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[모델 이름] [재설정 시간] [진행률 막대] [남은 비율]</span></span></code></pre></div><p><strong>필드 설명</strong>:</p><ul><li><strong>모델 이름</strong>: G3 Pro, G3 Image, G3 Flash, Claude</li><li><strong>재설정 시간</strong>: 다음 할당량까지 남은 시간(예: <code>4h 59m</code>, <code>2d 9h</code>)</li><li><strong>진행률 막대</strong>: 남은 비율 직관적 표시</li><li><strong>남은 비율</strong>: 0-100 숫자</li></ul><p><strong>다음을 확인해야 합니다</strong> 각 모델 한 줄씩, 할당량 및 재설정 시간 명확히 표시</p><h3 id="_3단계-다중-계정-상황-보기" tabindex="-1">3단계: 다중 계정 상황 보기 <a class="header-anchor" href="#_3단계-다중-계정-상황-보기" aria-label="Permalink to &quot;3단계: 다중 계정 상황 보기&quot;">​</a></h3><p><strong>왜 필요한가</strong> 여러 Google Cloud 계정이 있는 경우, 각각 따로 표시됩니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### another@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     2h 30m     ████████████░░░░░░░░ 75%</span></span>
<span class="line"><span>G3 Image   2h 30m     ████████████░░░░░░░░ 75%</span></span></code></pre></div><p><strong>다음을 확인해야 합니다</strong> 각 계정은 별도 섹션이며, 해당 계정의 4개 모델 할당량을 포함</p><h3 id="_4단계-할당량-경고-확인" tabindex="-1">4단계: 할당량 경고 확인 <a class="header-anchor" href="#_4단계-할당량-경고-확인" aria-label="Permalink to &quot;4단계: 할당량 경고 확인&quot;">​</a></h3><p><strong>왜 필요한가</strong> 초과 사용으로 인한 서비스 중단 방지</p><p>어느 모델의 사용률이 80%를 초과하면 경고 메시지가 표시됩니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     1h 30m     ████░░░░░░░░░░░░░░░ 20%</span></span>
<span class="line"><span>G3 Image   1h 30m     ████░░░░░░░░░░░░░░░ 20%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>⚠️ 사용률이 80% 이상에 도달했습니다</span></span></code></pre></div><p><strong>다음을 확인해야 합니다</strong> 경고 메시지는 해당 계정의 모델 목록 아래에 표시됩니다</p><h2 id="검사점-✅" tabindex="-1">검사점 ✅ <a class="header-anchor" href="#검사점-✅" aria-label="Permalink to &quot;검사점 ✅&quot;">​</a></h2><p>다음 확인을 완료하여 올바르게 수행했는지 확인하세요:</p><ul><li>[ ] <code>/mystatus</code> 실행 후 Google Cloud 할당량 정보를 볼 수 있음</li><li>[ ] 4개 모델의 이름 및 재설정 시간 이해</li><li>[ ] 진행률 막대 및 남은 비율 식별</li><li>[ ] 다중 계정이 있는 경우, 모든 계정의 할당량 볼 수 있음</li></ul><h2 id="주의-사항" tabindex="-1">주의 사항 <a class="header-anchor" href="#주의-사항" aria-label="Permalink to &quot;주의 사항&quot;">​</a></h2><h3 id="문제-1-google-cloud-할당량-보이지-않음" tabindex="-1">문제 1: Google Cloud 할당량 보이지 않음 <a class="header-anchor" href="#문제-1-google-cloud-할당량-보이지-않음" aria-label="Permalink to &quot;문제 1: Google Cloud 할당량 보이지 않음&quot;">​</a></h3><p><strong>가능한 원인</strong>:</p><ul><li>opencode-antigravity-auth 플러그인 설치 안 함</li><li>Google OAuth 인증 완료 안 함</li><li><code>antigravity-accounts.json</code> 파일이 존재하지 않거나 비어 있음</li></ul><p><strong>해결 방법</strong>:</p><ol><li>opencode-antigravity-auth 플러그인 설치</li><li>GitHub 저장소의 지침에 따라 인증 완료</li><li><code>/mystatus</code> 다시 실행</li></ol><h3 id="문제-2-특정-계정-오류-표시" tabindex="-1">문제 2: 특정 계정 오류 표시 <a class="header-anchor" href="#문제-2-특정-계정-오류-표시" aria-label="Permalink to &quot;문제 2: 특정 계정 오류 표시&quot;">​</a></h3><p><strong>가능한 원인</strong>:</p><ul><li>새로 고침 토큰 만료</li><li>projectId 누락</li></ul><p><strong>오류 예시</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>user@gmail.com: No project ID found</span></span></code></pre></div><p><strong>해결 방법</strong>:</p><ol><li>opencode-antigravity-auth 플러그인을 사용하여 해당 계정 다시 인증</li><li>인증 과정에서 프로젝트 ID를 올바르게 설정했는지 확인</li></ol><h3 id="문제-3-모델-데이터-또는-재설정-시간-비정상" tabindex="-1">문제 3: 모델 데이터 &quot;-&quot; 또는 재설정 시간 비정상 <a class="header-anchor" href="#문제-3-모델-데이터-또는-재설정-시간-비정상" aria-label="Permalink to &quot;문제 3: 모델 데이터 &quot;-&quot; 또는 재설정 시간 비정상&quot;">​</a></h3><p><strong>가능한 원인</strong>:</p><ul><li>API가 반환한 resetTime 필드가 누락되었거나 형식이 비정상</li><li>해당 모델에 할당량 정보가 없음</li></ul><p><strong>해결 방법</strong>:</p><ul><li>이것은 정상적인 상황이며, mystatus는 &quot;-&quot;를 표시하여 데이터를 사용할 수 없음을 나타냄</li><li>모든 모델이 &quot;-&quot;로 표시되면 네트워크 연결 또는 Google Cloud API 상태 확인</li></ul><h2 id="이-수업-요약" tabindex="-1">이 수업 요약 <a class="header-anchor" href="#이-수업-요약" aria-label="Permalink to &quot;이 수업 요약&quot;">​</a></h2><ul><li>Google Cloud Antigravity는 4개 모델 지원: G3 Pro, G3 Image, G3 Flash, Claude</li><li>각 모델은 독립적인 할당량 및 재설정 시간을 가짐</li><li>다중 계정 관리 지원, 각 계정은 별도로 표시</li><li>사용률이 80%를 초과하면 경고 메시지 표시</li></ul><h2 id="다음-수업-예고" tabindex="-1">다음 수업 예고 <a class="header-anchor" href="#다음-수업-예고" aria-label="Permalink to &quot;다음 수업 예고&quot;">​</a></h2><blockquote><p>다음 수업에서 **<a href="./../../advanced/google-setup/">Google Cloud 고급 구성: 다중 계정 및 모델 관리</a>**를 배웁니다.</p><p>학습할 내용:</p><ul><li>여러 Google Cloud 계정을 추가하고 관리하는 방법</li><li>4개 모델의 매핑 관계 이해</li><li>projectId와 managedProjectId의 차이</li></ul></blockquote><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>소스 코드 위치 확인하려면 클릭</strong></summary><blockquote><p>업데이트 시간: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>행번호</th></tr></thead><tbody><tr><td>모델 구성</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L69-L78" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>69-78</td></tr><tr><td>계정 조회 로직</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L304-L370" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>304-370</td></tr><tr><td>토큰 새로 고침</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L162-L184" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>162-184</td></tr><tr><td>할당량 추출</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L132-L157" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>132-157</td></tr><tr><td>출력 포맷팅</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L265-L294" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>265-294</td></tr><tr><td>유형 정의</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L78-L94" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>78-94</td></tr></tbody></table><p><strong>핵심 상수</strong>:</p><ul><li><code>GOOGLE_QUOTA_API_URL = &quot;https://cloudcode-pa.googleapis.com/v1internal:fetchAvailableModels&quot;</code>: Google Cloud 할당량 조회 API</li><li><code>GOOGLE_TOKEN_REFRESH_URL = &quot;https://oauth2.googleapis.com/token&quot;</code>: OAuth 토큰 새로 고침 API</li><li><code>USER_AGENT = &quot;antigravity/1.11.9 windows/amd64&quot;</code>: API 요청 User-Agent</li></ul><p><strong>핵심 함수</strong>:</p><ul><li><code>queryGoogleUsage()</code>: 모든 Antigravity 계정의 할당량 조회</li><li><code>fetchAccountQuota()</code>: 단일 계정의 할당량 조회</li><li><code>extractModelQuotas()</code>: API 응답에서 4개 모델의 할당량 추출</li><li><code>formatAccountQuota()</code>: 단일 계정의 할당량 표시 포맷팅</li></ul><p><strong>모델 매핑 규칙</strong>:</p><ul><li>G3 Pro는 <code>gemini-3-pro-high</code> 및 <code>gemini-3-pro-low</code> 지원, 주 키 우선 사용</li><li>Claude는 <code>claude-opus-4-5-thinking</code> 및 <code>claude-opus-4-5</code> 지원, 주 키 우선 사용</li><li>G3 Image 및 G3 Flash는 하나의 키만 존재</li></ul></details>`,70)])])}const h=o(s,[["render",i]]);export{u as __pageData,h as default};
